// src/components/Community.jsx
import React, { useState } from "react";
import { PIN_TYPES } from "./pinsConfig";

export default function Community({ onAddPin }) {
  const [type, setType] = useState("rain");
  const [lat, setLat]   = useState("");
  const [lng, setLng]   = useState("");
  const [message, setMessage] = useState("");

  const post = () => {
    if (!lat || !lng) return;
    onAddPin?.({
      id: crypto.randomUUID(),
      lat: parseFloat(lat),
      lng: parseFloat(lng),
      type,
      message,
      user: "Anon",
      timestamp: Date.now(),
    });
    setMessage(""); setLat(""); setLng("");
  };

  return (
    <div className="bg-black/60 backdrop-blur-md text-white rounded-2xl p-4 space-y-3">
      <div className="font-semibold">Quick Weather Reports</div>
      <div className="flex flex-wrap gap-2">
        {Object.entries(PIN_TYPES).map(([key, val]) => (
          <button
            key={key}
            onClick={() => setType(key)}
            className={`px-3 py-1.5 rounded-full text-sm border border-white/10 ${type===key ? "bg-white/10 ring-1 ring-purple-400" : "bg-black/40 hover:bg-black/30"}`}
            title={val.label}
          >
            {val.emoji} {val.label}
          </button>
        ))}
      </div>

      <textarea
        placeholder="Optional message"
        className="w-full bg-black/40 rounded px-2 py-2 text-sm"
        value={message}
        onChange={(e) => setMessage(e.target.value)}
      />

      <div className="flex gap-2">
        <input className="flex-1 bg-black/40 rounded px-2 py-1" placeholder="Latitude"  value={lat} onChange={(e)=>setLat(e.target.value)} />
        <input className="flex-1 bg-black/40 rounded px-2 py-1" placeholder="Longitude" value={lng} onChange={(e)=>setLng(e.target.value)} />
      </div>

      <button onClick={post} className="px-3 py-2 rounded-lg bg-purple-600 hover:bg-purple-500">
        Post report
      </button>
    </div>
  );
}
